mapper.select:
/* 포인트: 회원 행 잠금 */
SELECT USR_SN
FROM USERS
WHERE USR_SN = #{usrSn}
FOR UPDATE

/* 포인트: 참조 건별 유효 홀딩 금액 */
SELECT COALESCE(SUM(PT_LDG_AMT), 0)
FROM POINT_LEDGER
WHERE USR_SN = #{usrSn}
  AND PT_LDG_PT_TYPE_CD = 'PTLC0002'
  AND PT_LDG_REF_TYPE_CD = #{refTypeCd}
  AND PT_LDG_REF_SN = #{refSn}

mapper.insert:
/* 포인트: 원장 행 추가 */
INSERT INTO POINT_LEDGER (
    USR_SN, ACTOR_USR_SN,
    PT_LDG_REF_TYPE_CD, PT_LDG_REF_SN,
    PT_LDG_PT_TYPE_CD, PT_LDG_TYPE_CD,
    PT_LDG_AMT, PT_LDG_BAL_AFTER_AMT, PT_LDG_RSN_CN
) VALUES (
    #{usrSn}, #{actorUsrSn},
    #{ptLdgRefTypeCd}, #{ptLdgRefSn},
    #{ptLdgPtTypeCd}, #{ptLdgTypeCd},
    #{ptLdgAmt}, #{ptLdgBalAfterAmt}, #{ptLdgRsnCn}
)

mapper.select:
/* 포인트: 회원·참조 건별 유효 보관금 (음수 = 잔존) */
SELECT COALESCE(SUM(PT_LDG_AMT), 0)
FROM POINT_LEDGER
WHERE USR_SN = #{usrSn}
  AND PT_LDG_TYPE_CD IN ('PTLC0007', 'PTLC0013')
  AND PT_LDG_REF_TYPE_CD = #{refTypeCd}
  AND PT_LDG_REF_SN = #{refSn}

/* 포인트: 참조 건별 유효 보관금 (회원 무관, 음수 = 잔존) */
SELECT COALESCE(SUM(PT_LDG_AMT), 0)
FROM POINT_LEDGER
WHERE PT_LDG_TYPE_CD IN ('PTLC0007', 'PTLC0013')
  AND PT_LDG_REF_TYPE_CD = #{refTypeCd}
  AND PT_LDG_REF_SN = #{refSn}

/* 포인트: 참조 건별 기지급 정산 금액 */
SELECT COALESCE(SUM(PT_LDG_AMT), 0)
FROM POINT_LEDGER
WHERE PT_LDG_TYPE_CD = 'PTLC0008'
  AND PT_LDG_REF_TYPE_CD = #{refTypeCd}
  AND PT_LDG_REF_SN = #{refSn}

/* 포인트: 거래 건별 진행 중 거래 문제 건수 (정산 전환 차단 검사, 읽기 전용) */
SELECT COUNT(*)
FROM TRADE_DISPUTE
WHERE TRD_SN = #{trdSn}
  AND TRD_DSP_STATUS_CD IN ('TRDC0016', 'TRDC0017')
